(() => {
    const chunk = atob("");
    const editors = window.monaco?.editor?.getEditors?.() || [];
    if (!editors.length) return "no editor";
    const model = editors[0].getModel();
    const current = model.getValue();
    const next = current + chunk;
    model.setValue(next);
    return "append " + next.length;
  })()
